"""LangChain 어댑터 — LangChain BaseTool을 mantis ToolSpec으로 변환.

LangChain/LangGraph 생태계의 도구를 mantis ToolRegistry에 등록하여
에이전트/플로우 모드에서 실행할 수 있게 한다.
"""

from __future__ import annotations

import asyncio
import logging
from typing import Any

from mantis.tools.decorator import ToolSpec

logger = logging.getLogger(__name__)


def langchain_to_toolspec(lc_tool: Any) -> ToolSpec:
    """LangChain BaseTool → mantis ToolSpec 변환.

    Args:
        lc_tool: LangChain BaseTool 인스턴스.
            name, description, args_schema (또는 args) 속성 필요.

    Returns:
        mantis ToolSpec.
    """
    tool_name = getattr(lc_tool, "name", type(lc_tool).__name__)
    tool_desc = getattr(lc_tool, "description", f"LangChain tool: {tool_name}")

    # 파라미터 스키마 추출
    parameters = _extract_parameters(lc_tool)

    # 실행 함수 래핑
    async def _wrapped_execute(**kwargs: Any) -> dict:
        try:
            # LangChain 도구는 ainvoke 또는 invoke
            if hasattr(lc_tool, "ainvoke"):
                result = await lc_tool.ainvoke(kwargs)
            elif hasattr(lc_tool, "arun"):
                # 단일 인자 도구
                input_val = kwargs.get("input") or next(iter(kwargs.values()), "")
                result = await lc_tool.arun(input_val)
            elif hasattr(lc_tool, "invoke"):
                result = await asyncio.get_event_loop().run_in_executor(
                    None, lambda: lc_tool.invoke(kwargs),
                )
            elif hasattr(lc_tool, "run"):
                input_val = kwargs.get("input") or next(iter(kwargs.values()), "")
                result = await asyncio.get_event_loop().run_in_executor(
                    None, lambda: lc_tool.run(input_val),
                )
            else:
                # callable 폴백
                if asyncio.iscoroutinefunction(lc_tool):
                    result = await lc_tool(**kwargs)
                else:
                    result = await asyncio.get_event_loop().run_in_executor(
                        None, lambda: lc_tool(**kwargs),
                    )

            if isinstance(result, dict):
                return result
            return {"result": result}
        except Exception as e:
            logger.error("LangChain tool '%s' 실행 실패: %s", tool_name, e)
            return {"error": str(e)}

    return ToolSpec(
        name=tool_name,
        description=tool_desc,
        parameters=parameters,
        fn=_wrapped_execute,
        is_async=True,
    )


def langchain_tools_to_toolspecs(lc_tools: list[Any]) -> list[ToolSpec]:
    """여러 LangChain 도구를 mantis ToolSpec 목록으로 일괄 변환."""
    specs = []
    for tool in lc_tools:
        try:
            spec = langchain_to_toolspec(tool)
            specs.append(spec)
        except Exception as e:
            logger.warning("LangChain tool 변환 실패: %s — %s", getattr(tool, "name", "?"), e)
    return specs


def _extract_parameters(lc_tool: Any) -> dict[str, Any]:
    """LangChain 도구에서 파라미터 스키마를 추출."""
    parameters: dict[str, Any] = {}

    # args_schema (Pydantic BaseModel)에서 추출
    args_schema = getattr(lc_tool, "args_schema", None)
    if args_schema is not None:
        try:
            # Pydantic v2
            if hasattr(args_schema, "model_json_schema"):
                schema = args_schema.model_json_schema()
            # Pydantic v1
            elif hasattr(args_schema, "schema"):
                schema = args_schema.schema()
            else:
                schema = {}

            properties = schema.get("properties", {})
            required = set(schema.get("required", []))

            for name, prop in properties.items():
                parameters[name] = {
                    "type": prop.get("type", "string"),
                    "description": prop.get("description", name),
                }
                if name not in required:
                    parameters[name]["optional"] = True

            return parameters
        except Exception:
            pass

    # args 속성에서 추출 (LangChain의 args property)
    args = getattr(lc_tool, "args", None)
    if isinstance(args, dict):
        for name, prop in args.items():
            if isinstance(prop, dict):
                parameters[name] = {
                    "type": prop.get("type", "string"),
                    "description": prop.get("description", name),
                }
            else:
                parameters[name] = {
                    "type": "string",
                    "description": name,
                }
        return parameters

    # 폴백: 단일 input 파라미터
    parameters["input"] = {
        "type": "string",
        "description": "Tool input",
    }
    return parameters
